SELECT species.species_id, species.common_name, morphological_traits.leaf_size_cm2, morphological_traits.SLA_g_cm2
FROM species
JOIN morphological_traits ON species.species_id = morphological_traits.species_id;

SELECT * 
FROM species 
WHERE common_name = 'Agave rigida';

SELECT site_id, COUNT(DISTINCT species_id) AS unique_species_count
FROM data_collection
GROUP BY site_id;

SELECT u.user_name, r.project_name
FROM users u
JOIN research_projects r ON u.user_name = r.principal_investigator;

SELECT AVG(morphological_traits.leaf_size_cm2) AS average_leaf_size
FROM species
JOIN morphological_traits ON species.species_id = morphological_traits.species_id;

SELECT * 
FROM publications 
WHERE species_id = 0;
